{"content":"1: package httpclientprovider
2: 
3: import (
4: 	"net/http"
5: 	"time"
6: 
7: 	"github.com/grafana/grafana-plugin-sdk-go/backend/httpclient"
8: 	"github.com/prometheus/client_golang/prometheus"
9: )
10: 
11: // PrometheusMetrics groups some metrics for a PrometheusMetricsMiddleware
12: type PrometheusMetrics struct {
13: 	requestsCounter          prometheus.Counter
14: 	failureCounter           prometheus.Counter
15: 	durationSecondsHistogram prometheus.Histogram
16: 	inFlightGauge            prometheus.Gauge
17: }
18: 
19: // NewPrometheusMetricsMiddleware returns a new *PrometheusMetrics with pre-filled metrics, with the specified prefix
20: func NewPrometheusMetricsMiddleware(prefix string) *PrometheusMetrics {
21: 	return &PrometheusMetrics{
22: 		requestsCounter: prometheus.NewCounter(prometheus.CounterOpts{
23: 			Name: prefix + "_request_total",
24: 		}),
25: 		failureCounter: prometheus.NewCounter(prometheus.CounterOpts{
26: 			Name: prefix + "_failure_total",
27: 		}),
28: 		durationSecondsHistogram: prometheus.NewHistogram(prometheus.HistogramOpts{
29: 			Name: prefix + "_request_duration_seconds",
30: 		}),
31: 		inFlightGauge: prometheus.NewGauge(prometheus.GaugeOpts{
32: 			Name: prefix + "_in_flight_request",
33: 		}),
34: 	}
35: }
36: 
37: // Register registers the metrics in the current PrometheusMetrics into the provided registry
38: func (m *PrometheusMetrics) Register(registry prometheus.Registerer) error {
39: 	for _, collector := range []prometheus.Collector{
40: 		m.requestsCounter, m.failureCounter, m.durationSecondsHistogram, m.inFlightGauge,
41: 	} {
42: 		if err := registry.Register(collector); err != nil {
43: 			return err
44: 		}
45: 	}
46: 	return nil
47: }
48: 
49: // MustRegister is like Register, but, in case of failure, it panics instead of returning an error
50: func (m *PrometheusMetrics) MustRegister(registry prometheus.Registerer) {
51: 	if err := m.Register(registry); err != nil {
52: 		panic(err)
53: 	}
54: }
55: 
56: // WithMustRegister calls MustRegister and returns itself. This is to allow to chain the method call
57: // upon initialization, useful when declaring metrics in the global scope:
58: //
59: //	var svcMetrics = NewPrometheusMetricsMiddleware("my_client").WithMustRegister(prometheus.DefaultRegisterer)
60: func (m *PrometheusMetrics) WithMustRegister(registry prometheus.Registerer) *PrometheusMetrics {
61: 	m.MustRegister(registry)
62: 	return m
63: }
64: 
65: // PrometheusMetricsMiddleware is a middleware that will mutate the in flight, requests, duration and
66: // failure count on the provided *PrometheusMetrics instance. This can be used to count the number of requests,
67: // successful requests and errors that go through the httpclient, as well as to track the response times.
68: // For the metrics to be exposed properly, the provided *PrometheusMetrics should already be registered in a Prometheus
69: // registry.
70: func PrometheusMetricsMiddleware(metrics *PrometheusMetrics) httpclient.Middleware {
71: 	return httpclient.MiddlewareFunc(func(opts httpclient.Options, next http.RoundTripper) http.RoundTripper {
72: 		return httpclient.RoundTripperFunc(func(req *http.Request) (*http.Response, error) {
73: 			startTime := time.Now()
74: 			metrics.inFlightGauge.Inc()
75: 
76: 			res, err := next.RoundTrip(req)
77: 
78: 			metrics.inFlightGauge.Dec()
79: 			metrics.requestsCounter.Inc()
80: 			metrics.durationSecondsHistogram.Observe(time.Since(startTime).Seconds())
81: 			if err != nil || (res != nil && (res.StatusCode < 200 || res.StatusCode > 299)) {
82: 				metrics.failureCounter.Inc()
83: 			}
84: 
85: 			return res, err
86: 		})
87: 	})
88: }
